import React, { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Image, Form} from 'react-bootstrap'
import MainLayout from "../../components/Layout";
import BASE_URL from "../../config";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

function Employee({ setModuleName }) {
   const [dob, setDOB] = useState(null);
   const [joiningDate, setJoiningDate] = useState(null);
   const [headNoRecord, setHeadNoRecord] = useState(false);
   const [religions, setReligion] = useState([]);
   const [selectedReligion, setSelectedReligion] = useState("");
   const [titles, setTitle] = useState([]);
   const [selectedTitle, setSelectedTitle] = useState("");
   const [designations, setDesignation] = useState([]);
   const [selectedDesignation, setSelectedDesignation] = useState("");
   const [states, setStates] = useState([]);
   const [selectedState, setSelectedState] = useState("");
   const [district, setDistrict] = useState([]);
   const [selectedDistrict, setSelectedDistrict] = useState("");
   const [errors, setErrors] = useState({});
   const [offices, setOffices] = useState([]);

   const [employee, setEmployee] = useState({ emp_code: "",title_id:0, emp_name: "",emp_name_local:"",emp_father_name: "",emp_father_name_local:"",
   emp_mother_name: "",emp_mother_name_local:"",emp_spouse_name: "",emp_spouse_name_local:"",emp_photo: "",dob:"",gender:"",religion_id:0,state_id:0,
   district_id:0, address: "",mobile_no1: "", mobile_no2: "", email_id: "", joining_office: "", joining_date: "",desig_id:0,emp_type:"",action: "S", status: "A",});

   useEffect(() => {
      setModuleName("Employee Management");
      setHeadNoRecord(true);
      loadStates();
      loadDesignation();
      loadNameTitle();
      loadReligion();
   }, []);

   const loadDesignation = async () => {
            try {
               const response = await fetch(`${BASE_URL}/user/get-designation`);
               const data = await response.json();
               setDesignation(data);
            } catch (err) {
               console.log(err);
            }
         };   
   const loadNameTitle = async () => {
            try {
               const response = await fetch(`${BASE_URL}/user/get-nametitle`);
               const data = await response.json();
               setTitle(data);
            } catch (err) {
               console.log(err);
            }
         };
   const loadReligion = async () => {
            try {
               const response = await fetch(`${BASE_URL}/user/get-religion`);
               const data = await response.json();
               setReligion(data);
            } catch (err) {
               console.log(err);
            }
         };
   const loadStates = async () => {
      try {
         const response = await fetch(`${BASE_URL}/user/get-state`);
         const data = await response.json();
         setStates(data);
      } catch (err) {
         console.log(err);
      }
   };
   const loadDistrict = async (StateID) => {
      try {
         const response = await fetch(`${BASE_URL}/user/get-district`,
            {
            method: "POST",
            headers: {
               "Content-Type": "application/json",
            },
            body: JSON.stringify({
               state_id: Number(StateID),
            }),
            }
         );
            const data = await response.json();
            setDistrict(data);
         } catch (err) {
            console.log(err);
         }
   };
   const loadEmployeeList = async (officeLevelID = "", officeID = "",searchtxt="") => {
      try {
         const response = await fetch(`${BASE_URL}/user/getoffices`,
            {
            method: "POST",
            headers: { "Content-Type": "application/json", },
            body: JSON.stringify({ office_level_id: officeLevelID ? Number(officeLevelID): 0, office_id: officeID || "",
            }),
            }
         );
         const data = await response.json();
         const employeeList = Array.isArray(data) ? data : [];
         
         setEmployee(employeeList);
         //console.log(officeList.length);
         if (employeeList.length === 0) {
            setHeadNoRecord(true);
         } else {
            setHeadNoRecord(false);
         }
         console.log(headNoRecord);

      } catch (err) {
         console.log(err);
         setHeadNoRecord(true);
      }
   };

   const validateForm = () => {
      let tempErrors = {};

      // Office Name
      if (!employee.emp_code.trim()) {
         tempErrors.emp_code = "Employee code is required";
      }
      if (!employee.emp_name.trim()) {
         tempErrors.emp_name = "Employee name is required";
      }
      if (!employee.mobile_no1.trim()) {
      } else if (!/^[0-9]{10}$/.test(employee.mobile_no1)) {
         tempErrors.mobile_no1 = "Mobile number must be 10 digits";
      }
      if (!employee.mobile_no2.trim()) {
      } else if (!/^[0-9]{10}$/.test(employee.mobile_no2)) {
         tempErrors.mobile_no2 = "Mobile number 2 must be 10 digits";
      }
      if (!employee.email_id.trim()) {
      } else if (
         !/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i.test(employee.email_id)
      ) {
         tempErrors.email_id = "Invalid email address";
      }

      setErrors(tempErrors);

      return Object.keys(tempErrors).length === 0;
   };

   const saveOffice = async (e) => {
      e.preventDefault();
      if (!validateForm()) {
         return;
      }
      const employeeData = {
         ...employee,
         action: "S",
         status: "A",
      };


      try {
         const response = await fetch(`${BASE_URL}/user/addupdateemployee`,
            {
            method: "POST",
            credentials: "include",
            headers: {
               "Content-Type": "application/json",
            },
            body: JSON.stringify(employeeData),
            }
         );

         const data = await response.json();

         if (response.ok) {
            let message = "Employee Details Saved Successfully";

            if (employeeData.action === "U") {
            message = "Employee updated successfully";
            }

            if (employeeData.action === "R") {
            message = "Employee deleted successfully";
            }
            alert(message);
            loadEmployeeList();
            // Clear form
            setEmployee({emp_code: "",title_id:0, emp_name: "",emp_name_local:"",emp_father_name: "",emp_father_name_local:"", emp_mother_name: "",
            emp_mother_name_local:"",emp_spouse_name: "",emp_spouse_name_local:"",emp_photo: "",dob:"",gender:"",religion_id:0,state_id:0, district_id:0,
            address: "",mobile_no1: "", mobile_no2: "", email_id: "", joining_office: "", joining_date: "",desig_id:0,emp_type:"",action: "S", status: "A",});

            setSelectedState("");
            setSelectedDesignation("");
            setSelectedReligion("");
            setSelectedTitle("");
            setDistrict([]);

         } else {
            alert(data.message || "Failed to save employee");
         }
      } catch (err) {
         console.log(err);
         alert("Error while saving employee");
      }
   };

  return (
      <div className="conatiner-fluid content-inner mt-n5 px-3 py-0">
         <div className="row g-3 py-3">
            <div class="col-xl-2 col-lg-4">
      <div className="acard summary mb-2">
            <div className="icon-wrap" style={{ background: "#eff6ff", color: "#1d4ed8" }} >
               <i className="fa fa-user"></i>
            </div>
            <div className="d-flex flex-column align-items-end">
               <p className="acard-stat mb-0" id="hdTotOffice">{offices[0]?.tot_office  || 0}</p>
               <p className="acard-title mb-0">Total Employees</p>
            </div>
            </div>
      <div className="acard summary mb-2">
         <div className="icon-wrap" style={{background:"#f0fdf4", color:"#16a34a"}}>
            <i className="fa fa-user"></i>
         </div>
            <div className="d-flex flex-column align-items-end">
               <p className="acard-stat mb-0" id="hdTotHQOffice">{offices[0]?.tot_hq  || 0}</p>
               <p className="acard-title mb-0">Headquarter</p>
            </div>
         </div>
      <div className="acard summary mb-2">
         <div className="icon-wrap" style={{background:"#fffbeb", color:"#d97706"}}>
            <i className="fa fa-user"></i>
         </div>
            <div className="d-flex flex-column align-items-end">
               <p className="acard-stat mb-0" id="hdTotRegOffice">{offices[0]?.tot_regionalofc  || 0}</p>
               <p className="acard-title mb-0">Regional Offices</p>
            </div>
         </div>
      <div className="acard summary mb-2">
         <div className="icon-wrap" style={{background:"#fef2f2", color:"#dc2626"}}>
            <i className="fa fa-user"></i>
         </div>
            <div className="d-flex flex-column align-items-end">
               <p className="acard-stat mb-0" id="hdTotDistOffice">{offices[0]?.tot_distofc  || 0}</p>
               <p className="acard-title mb-0">District Offices</p>
            </div>
         </div>
         <div class="card">
            <div class="card-header d-flex justify-content-between border-0">
               <div class="header-title">
                  <h5 class="card-title">Instructions</h5>
               </div>
            </div>
            <div class="card-body pt-0">
               <ol className="form-label col-form-label col-form-label-sm text-danger px-2">
                  <li>Here you can add employee along with their basic details.</li>
                  <li>You can also update employee details.</li>
                  <li>All fields marked <span style={{color: "Red"}}>*</span> are mandatory.</li>
               </ol>
               </div>
               </div>
            </div>
            <div className="col-xl-4 col-lg-3">
               <div className="card">
            <div className="card-header border-0">
        <div className="d-flex justify-content-between align-items-center mb-2">
          <div className="header-title">
            <h5 className="card-title mb-0">Employee List</h5>
          </div>
        </div>
      
        <div className="d-flex flex-nowrap gap-2 align-items-center w-100">
      
        {/* Office Level Dropdown */}
        <div className="flex-fill">
          <select id="drpSearchOfcLevel" className="form-select form-select-sm" >
              <option value="">Select Office Level</option>
          </select>
        </div>
      
        {/* Office Dropdown */}
        <div className="flex-fill">
          <select id="drpSearchOfcID" className="form-select form-select-sm">
          </select>
        </div>
      
        {/* Buttons */}
        <div className="flex-shrink-0">
          <button className="btn btn-primary btn-sm" type="button" data-bs-toggle="tooltip" data-bs-placement="top" data-bs-custom-class="white-tooltip" data-bs-title="Search" >
            <i className="fa fa-search text-white"></i>&nbsp;
          </button>
          &nbsp;
          <button className="btn btn-danger btn-sm" type="button" data-bs-toggle="tooltip" data-bs-placement="top" data-bs-custom-class="white-tooltip" data-bs-title="Reset" >
            <i className="fa fa-refresh text-white"></i>&nbsp;
          </button>
        </div>
      
      </div>
      </div>
      <div className="card-body">
         <div className="table-responsive">                       
            {headNoRecord && (
                     <h4  className="text-muted p-5 text-center fw-bold" style={{display:"none"}}>No Record Found</h4>
            )}
         </div>
      </div>
      </div>
      </div>
      <div className="col-xl-6 col-lg-6">
         <div className="card">
            <div className="card-header d-flex justify-content-between border-0">
               <div className="header-title">
                  <h5 className="card-title">Add New Employee</h5>
               </div>
            </div>
            <div className="card-body">
               <div className="new-user-info">
                  <Form>
                     <h6>1. General Details</h6>
                     <div className="row">
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="fname">Emp Code <span style={{color: "Red"}}>*</span></label>
                           <input type="text" className={`form-control form-control-sm ${errors.emp_code ? "is-invalid" : ""}`} id="tbempcode"
                           placeholder="Enter Employee Code" value={employee.emp_code} onChange={(e) => setEmployee({ ...employee, emp_code: e.target.value }) } />
                     <div className="invalid-feedback">{errors.emp_code}</div>
                        </div>
                     
                     <div className="form-group col-md-8"></div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="fname">Title <span style={{color: "Red"}}>*</span></label>
                           <select className={`selectpicker form-select form-select-sm `} data-style="py-0" value={selectedTitle} 
                              onChange={(e) => { const TitleID = e.target.value; setSelectedTitle(TitleID);}}>
                              <option value="">Select Title</option>
                              {titles.map((title) => (
                                 <option key={title.title_id} value={title.title_id}>
                                    {title.title_name}
                                 </option>
                              ))}
                           </select>
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="fname">Name <span style={{color: "Red"}}>*</span></label>
                           <input type="text" className={`form-control form-control-sm ${errors.emp_name ? "is-invalid" : ""}`} id="tbempname"
                           placeholder="Enter Employee Name" value={employee.emp_name} onChange={(e) => setEmployee({ ...employee, emp_name: e.target.value }) } />
                     <div className="invalid-feedback">{errors.emp_name}</div>
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="lname">Name (Local)</label>
                              <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Employee Name(Local)"
                               value={employee.emp_name_local} onChange={(e) => setEmployee({ ...employee, emp_name_local: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="fname">Father Name</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Father Name"
                               value={employee.emp_father_name} onChange={(e) => setEmployee({ ...employee, emp_father_name: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="lname">Father Name (Local)</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Father Name(Local)"
                               value={employee.emp_father_name_local} onChange={(e) => setEmployee({ ...employee, emp_father_name_local: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="fname">Mother Name</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Mother Name"
                               value={employee.emp_mother_name} onChange={(e) => setEmployee({ ...employee, emp_mother_name: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="lname">Mother Name (Local)</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Mother Name(Local)"
                               value={employee.emp_mother_name_local} onChange={(e) => setEmployee({ ...employee, emp_mother_name_local: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="fname">Spouse Name</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Spouse Name"
                               value={employee.emp_spouse_name} onChange={(e) => setEmployee({ ...employee, emp_spouse_name: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="lname">Spouse Name (Local)</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Spouse Name(Local)"
                               value={employee.emp_spouse_name_local} onChange={(e) => setEmployee({ ...employee, emp_spouse_name_local: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="fname">Date of Birth</label><br/>
                           <div className="input-group">
                           <DatePicker selected={dob} onChange={(date) => setDOB(date)} className="form-control form-control-sm w-100"
                              dateFormat="dd/MM/yyyy" showMonthDropdown showYearDropdown dropdownMode="select" placeholderText="DD/MM/YYYY" />
                           <span className="input-group-text"> <i className="fa fa-calendar"></i> </span>
                           </div>
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="lname">Gender</label>
                              <select className={`selectpicker form-select form-select-sm`} data-style="py-0" value={selectedDistrict}>
                                 <option value="">Select Gender</option>
                                 <option value={`M`}>Male</option>
                                 <option value={`F`}>Female</option>
                                 <option value={`O`}>Other</option>
                                 </select>
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="lname">Religion</label>
                              <select className={`selectpicker form-select form-select-sm `} data-style="py-0" value={selectedReligion} 
                              onChange={(e) => { const ReligionID = e.target.value; setSelectedReligion(ReligionID);}}>
                              <option value="">Select Religion</option>
                              {religions.map((religion) => (
                                 <option key={religion.religion_id} value={religion.religion_id}>
                                    {religion.religion_name}
                                 </option>
                              ))}
                           </select>
                        </div>
                        </div>
                        <hr className="my-2" />
                     <h6>2. Contact Details</h6>
                     <div class="row">
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="mobno">Mobile Number</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Father Name(Local)"
                               value={employee.mobile_no1} onChange={(e) => setEmployee({ ...employee, mobile_no1: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="mobno">Mobile Number 2</label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Father Name(Local)"
                               value={employee.mobile_no2} onChange={(e) => setEmployee({ ...employee, mobile_no2: e.target.value }) } />
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="email">Email<span style={{color: "Red"}}>*</span></label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Father Name(Local)"
                               value={employee.email_id} onChange={(e) => setEmployee({ ...employee, emp_name_email_idlocal: e.target.value }) } />
                        </div>   
                        <div className="form-group col-sm-4">
                           <label className="form-label col-form-label col-form-label-sm">State</label>
                           <select className={`selectpicker form-select form-select-sm ${errors.state_id ? "is-invalid" : ""}`} data-style="py-0" value={selectedState} 
                     onChange={(e) => { const StateID = e.target.value; setSelectedState(StateID); loadDistrict(StateID);}}>
                           <option value="">Select State</option>
                           {states.map((state) => (
                              <option key={state.state_id} value={state.state_id}>
                                 {state.state_name}
                              </option>
                           ))}
                     </select>
                        </div>
                        <div className="form-group col-sm-4">
                           <label className="form-label col-form-label col-form-label-sm">District</label>
                           <select className={`selectpicker form-select form-select-sm`} data-style="py-0" value={selectedDistrict}>
                                 <option value="">Select District</option>
                                 {district.map((d) => (
                                    <option key={d.district_id} value={d.district_id}>
                                       {d.district_name}
                                    </option>
                                 ))}
                                 </select>
                        </div>
                        <div className="form-group col-md-12">
                           <label className="form-label col-form-label col-form-label-sm" for="add1">Address </label>
                           <input type="text" className={`form-control form-control-sm`} id="tbempnamelocal" placeholder="Enter Father Name(Local)"
                               value={employee.address} onChange={(e) => setEmployee({ ...employee, address: e.target.value }) } />
                        </div>
                     </div>
                     <hr className="my-2" />
                     <h6>3. Office Details</h6>
                     <div class="row">
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="add1">Joining Office </label>
                           <select className={`selectpicker form-select form-select-sm`} data-style="py-0" value={selectedDistrict}>
                                 <option value="">Select Joining Office</option>
                                 </select>
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="mobno">Joining Date</label><br/>
                           <div className="input-group">
                           <DatePicker selected={joiningDate} onChange={(date) => setJoiningDate(date)} className="form-control form-control-sm w-100"
                              dateFormat="dd/MM/yyyy" showMonthDropdown showYearDropdown dropdownMode="select" placeholderText="DD/MM/YYYY" />
                           <span className="input-group-text"> <i className="fa fa-calendar"></i> </span>
                           </div>
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="email">Designation</label>
                              <select className={`selectpicker form-select form-select-sm `} data-style="py-0" value={selectedDesignation} 
                              onChange={(e) => { const DesigID = e.target.value; setSelectedDesignation(DesigID);}}>
                              <option value="">Select Designation</option>
                              {designations.map((designation) => (
                                 <option key={designation.desig_id} value={designation.desig_id}>
                                    {designation.desig_name}
                                 </option>
                              ))}
                           </select>
                        </div>
                        <div className="form-group col-md-4">
                           <label className="form-label col-form-label col-form-label-sm" for="email">Employee Type</label>
                              <select className={`selectpicker form-select form-select-sm`} data-style="py-0" value={selectedDistrict}>
                                 <option value="">Select Employee Type</option>
                                 <option value={`R`}>Regular</option>
                                 <option value={`C`}>Contractual</option>
                                 </select>
                        </div>
                     </div>
                     <button type="submit" className="btn btn-primary"><i className="fa fa-check"></i>Save </button>&nbsp;&nbsp;
                     <button type="button" className="btn btn-danger" ><i className="fa fa-times"></i> Cancel </button>
                  </Form>
               </div>
            </div>
         </div>
      </div>
      </div>
   </div>
 );
}

export default Employee;
